local strings = {
    [SI_BAV_PANEL_NAME] = "Bureau of Acceptable Views",
    [SI_BAV_PANEL_DISPLAY_NAME] = "|c6FCB9FBureau|r of Acceptable Views",
    [SI_BAV_PANEL_DESCRIPTION] = "Аккуратно расширяет управление камерой в ограниченных состояниях, улучшает возврат из вида от первого лица и даёт гибкие настройки сохранения зума. Ввод с контроллера обрабатывается стандартными средствами игры.",
    [SI_BAV_PANEL_INTRO] = "|c6FCB9FАдаптивное управление камерой|r для ситуаций, когда ESO обычно ограничивает зум. Bureau of Acceptable Views делает переход между видом от первого и от третьего лица более предсказуемым, плавным и удобным.",
    [SI_BAV_PANEL_OVERVIEW] = "|c8C8A82• Работает верхом, в воде и в особых формах\n• Запоминает предпочитаемую дистанцию от третьего лица\n• Может сохранять вид от первого лица между релогами и сменой зон\n• Поддерживает быструю настройку через чат-команды|r",
    [SI_BAV_PANEL_TIPS] = "|cC5C29EБыстрый доступ|r\nИспользуйте |cFFFFFF/bav|r для статуса, |cFFFFFF/bav settings|r чтобы открыть эту панель, |cFFFFFF/bav config|r для настройки в чате и |cFFFFFF/bav help|r для полного списка команд.",
    [SI_BAV_HEADER_CAMERA] = "|cC5C29EТонкая настройка камеры|r",
    [SI_BAV_HEADER_BEHAVIOR] = "|cC5C29EПоведение и сохранение|r",
    [SI_BAV_HEADER_DEBUG] = "|cC5C29EДиагностика|r",
    [SI_BAV_SECTION_CAMERA_DESCRIPTION] = "|c8C8A82Настройте, насколько плавно и быстро ощущается зум, и задайте безопасную резервную дистанцию от третьего лица.|r",
    [SI_BAV_SECTION_BEHAVIOR_DESCRIPTION] = "|c8C8A82Определите, как аддон должен восстанавливать камеру после релогов, смены зон и возврата из первого лица.|r",
    [SI_BAV_SECTION_DEBUG_DESCRIPTION] = "|c8C8A82Полезно для проверки редких случаев и диагностики странного поведения камеры. Для обычной игры лучше держать уровень ниже, чтобы не засорять чат.|r",
    [SI_BAV_HEADER_DYNAMIC_FOV] = "Динамическое поле зрения",
    [SI_BAV_SECTION_DYNAMIC_FOV_DESCRIPTION] = "|c8C8A82Слегка расширяет или сужает поле зрения от третьего лица в зависимости от того, насколько вы отдалили камеру, создавая более кинематографичное ощущение глубины. |r|c6FCB9FВключено по умолчанию.|r",
    [SI_BAV_HEADER_CONTEXT_PRESETS] = "Контекстные пресеты",
    [SI_BAV_SECTION_CONTEXT_PRESETS_DESCRIPTION] = "|c8C8A82Автоматически подстраивают кадрирование камеры под конкретные игровые состояния. Каждое состояние включается отдельно, а общая сила эффекта масштабируется ползунком интенсивности. |r|cD0905EПо умолчанию отключено.|r",
    [SI_BAV_PANEL_FOOTER] = "|c6FCB9FПримечание:|r изменения слайдеров и переключателей сразу нормализуются и сохраняются.",
    [SI_BAV_SLASH_HINT] = "|cC5C29EБыстрые команды|r: |cFFFFFF/bav|r  |cC5C29E•|r  |cFFFFFF/bav settings|r  |cC5C29E•|r  |cFFFFFF/bav config|r  |cC5C29E•|r  |cFFFFFF/bav help|r",

