    [SI_BAV_SETTING_ZOOM_STEP_NAME] = "Шаг зума",
    [SI_BAV_SETTING_ZOOM_STEP_TOOLTIP] = "Насколько меняется зум за одно действие. Меньшие значения ощущаются плавнее, большие - быстрее.",
