    [SI_BAV_SETTING_MIN_MOUNTED_TOOLTIP] = "Резервная дистанция от третьего лица, используемая, когда нет корректного запомненного значения.",
    [SI_BAV_SETTING_PRESERVE_FPV_NAME] = "Сохранять вид от первого лица между релогами и зонами",
    [SI_BAV_SETTING_PRESERVE_FPV_TOOLTIP] = "Если включено, выход из игры или смена зоны в виде от первого лица восстановят его после загрузки. Если выключено, аддон вместо этого вернёт сохранённую дистанцию от третьего лица.",
    [SI_BAV_SETTING_DEBUG_MODE_NAME] = "Режим отладки",
    [SI_BAV_SETTING_DEBUG_MODE_TOOLTIP] = "Управляет объёмом диагностических сообщений, которые аддон выводит в чат.",
    [SI_BAV_SETTING_RESET_CONFIG_NAME] = "Сбросить к нейтральной камере",
    [SI_BAV_SETTING_RESET_CONFIG_TOOLTIP] = "Восстановить основные значения зума и выключить все необязательные функции - для чистой, «ванильной» камеры. Учтите: это не то же самое, что свежая установка - динамический FOV и FOV от скорости поставляются включёнными, но сброс намеренно их выключает, давая вам нейтральную отправную точку.",
    [SI_BAV_SETTING_RESET_CONFIG_CONFIRM] = "Будут восстановлены основные значения зума и выключены все необязательные функции (динамический FOV, FOV от скорости, контекстные пресеты, камера через плечо). Ваши изменения будут потеряны. Продолжить?",
    [SI_BAV_SETTING_RESET_CAMERA_NAME] = "Сбросить состояние камеры",
    [SI_BAV_SETTING_RESET_CAMERA_TOOLTIP] = "Немедленно вернуть управление камерой вам: снять активный контекстный пресет и удержание угла обзора, восстановить ваш исходный кадр и сбросить активное и сохранённое состояние камеры, используя текущий резервный зум.",
    [SI_BAV_SETTING_RESET_CAMERA_CONFIRM] = "Активный пресет и удержание угла обзора будут сняты, а камера сброшена к текущему резервному зуму. Продолжить?",
    [SI_BAV_SETTING_RESET_CAMERA_NOTE] = "|c6FCB9FСтраховка:|r воспринимайте это как ремень безопасности. Аддон очень надёжно работает с настройками и не должен оставлять камеру в некорректном состоянии, так что, скорее всего, это вам никогда не понадобится. Кнопка здесь исключительно ради тех самых 0.001% вероятности - один клик мгновенно вернёт вам полный контроль над камерой.",
    [SI_BAV_SETTING_PRINT_CONFIG_NAME] = "Показать текущую конфигурацию",
    [SI_BAV_SETTING_PRINT_CONFIG_TOOLTIP] = "Вывести текущую конфигурацию аддона в чат.",
    [SI_BAV_HEADER_CONFIGURATION] = "|cC5C29EКонфигурация|r",
    [SI_BAV_SECTION_CONFIGURATION_DESCRIPTION] = "|c8C8A82Просмотрите текущие настройки или сбросьте к нейтральной камере: основные значения зума восстанавливаются, а все необязательные функции выключаются. Сброс затрагивает только конфигурацию аддона и не трогает активную камеру.|r",
    [SI_BAV_HEADER_CAMERA_ACTIONS] = "|cC5C29EУправление камерой|r",
    [SI_BAV_SECTION_CAMERA_ACTIONS_DESCRIPTION] = "|c8C8A82Верните себе управление активной камерой одним кликом, независимо от сохранённой конфигурации.|r",
    [SI_BAV_SETTING_SELFCHECK_NAME] = "Запустить самопроверку",
    [SI_BAV_SETTING_SELFCHECK_TOOLTIP] = "Запустить проверку надёжности сейчас: проверить внутренние инварианты аддона и вывести в чат объём занимаемых им данных. В отличие от автоматического тихого прохода, исправное состояние тоже отображается.",
    [SI_BAV_SETTING_DUMP_STATE_NAME] = "Полный дамп состояния",
    [SI_BAV_SETTING_DUMP_STATE_TOOLTIP] = "Вывести в чат полный снимок текущего состояния камеры и игрока - для диагностики или отчётов об ошибках.",
    [SI_BAV_SETTING_CONFLICT_ADVISORY_NAME] = "Предупреждение о конфликте в чат",
    [SI_BAV_SETTING_CONFLICT_ADVISORY_TOOLTIP] = "Если другой аддон заставляет камеру быстро переключать вид, BAV отступает со своей обработкой, чтобы разорвать петлю. Когда опция включена, в чат также выводится однократное нейтральное уведомление. Сама защита работает всегда; эта опция управляет только сообщением в чате.",

    [SI_BAV_SETTING_DYNAMIC_FOV_ENABLED_NAME] = "Включить динамическое поле зрения",
    [SI_BAV_SETTING_DYNAMIC_FOV_ENABLED_TOOLTIP] = "Если включено, поле зрения от третьего лица плавно меняется между ближним и дальним значением по мере приближения и отдаления камеры.",
    [SI_BAV_SETTING_DYNAMIC_FOV_SMOOTH_NAME] = "Плавные переходы FOV",
