    [SI_BAV_SETTING_DYNAMIC_FOV_NEAR_NAME] = "Поле зрения (камера приближена)",
    [SI_BAV_SETTING_DYNAMIC_FOV_NEAR_TOOLTIP] = "Поле зрения, применяемое когда камера приближена до упора. Ограничено допустимым диапазоном FOV движка, поэтому любое значение здесь безопасно.",
    [SI_BAV_SETTING_DYNAMIC_FOV_FAR_NAME] = "Поле зрения (камера отдалена)",
    [SI_BAV_SETTING_DYNAMIC_FOV_FAR_TOOLTIP] = "Поле зрения, применяемое когда камера отдалена до упора. Разведите его дальше от значения приближения для более сильного эффекта, сведите ближе чтобы смягчить, или сделайте равными чтобы полностью убрать эффект.",
    [SI_BAV_SETTING_DYNAMIC_FOV_RESET_NAME] = "Сбросить диапазон FOV",
    [SI_BAV_SETTING_DYNAMIC_FOV_RESET_TOOLTIP] = "Очистить ваши значения ближнего/дальнего FOV и вернуться к стандартному диапазону поля зрения движка.",
    [SI_BAV_SETTING_PRESETS_ENABLED_NAME] = "Включить контекстные пресеты",
    [SI_BAV_SETTING_PRESETS_ENABLED_TOOLTIP] = "Главный переключатель контекстных пресетов. Когда выключен, ни одна из настроек кадрирования по состояниям ниже не применяется.",
    [SI_BAV_LABEL_PRESET_STATES] = "|cC5C29EВыберите стиль для каждого состояния|r",
    [SI_BAV_LABEL_PRESET_STATES_HELP] = "|c8C8A82Выберите «Выключено», чтобы отключить состояние; ползунок интенсивности влияет только на состояния с непустым стилем.|r",
    [SI_BAV_SETTING_PRESET_INTENSITY_NAME] = "Интенсивность пресетов",
    [SI_BAV_SETTING_PRESET_INTENSITY_TOOLTIP] = "Масштабирует, насколько сильно активные пресеты смещают камеру: от 0% (без эффекта) до 100% (полный эффект).",
    [SI_BAV_SETTING_PRESET_STATE_INTENSITY_NAME] = "Интенсивность состояния",
    [SI_BAV_SETTING_PRESET_STATE_INTENSITY_TOOLTIP] = "Масштабирует кадрирование этого состояния поверх общей интенсивности пресетов: от 0% (без эффекта) до 100% (полная сила стиля). Недоступно, когда стиль этого состояния - «Выкл».",
    [SI_BAV_SETTING_PRESET_COALESCE_NAME] = "Задержка возврата",
    [SI_BAV_SETTING_PRESET_COALESCE_TOOLTIP] = "Сколько времени выход из этого состояния ждёт перед возвратом камеры. Небольшая задержка позволяет быстрому выходу-и-возврату (например, бой закончился и тут же начался снова) свестись к нулевому действию вместо рывка камеры. «Выкл» возвращает камеру сразу, без сглаживания. По умолчанию отключено для всех состояний.",
