    [SI_BAV_HEADER_SHOULDER] = "Камера через плечо",
    [SI_BAV_SECTION_SHOULDER_DESCRIPTION] = "|c8C8A82Смещает камеру от третьего лица за одно плечо для сфокусированного кинематографичного кадра. Выберите способ срабатывания: |r|c6FCB9FАвто|r|c8C8A82 смещает автоматически в выбранных состояниях; |r|c6FCB9FВручную|r|c8C8A82 смещает по команде |cFFFFFF/bav shoulder|r|c8C8A82. Пока опция включена, она перехватывает плечо у пресета скрытности. |r|cD0905EПо умолчанию отключено.|r",
    [SI_BAV_SETTING_SHOULDER_MODE_NAME] = "Режим плеча",
    [SI_BAV_SETTING_SHOULDER_MODE_TOOLTIP] = "«Выкл» отключает функцию. «Авто» автоматически смещает камеру за выбранное плечо, пока вы находитесь в любом из выбранных состояний. «Вручную» позволяет смещать камеру по команде /bav shoulder (автоматическое поведение при этом отключено). Два активных режима взаимоисключающие.",
    [SI_BAV_SETTING_SHOULDER_MODE_OFF] = "Выкл",
    [SI_BAV_SETTING_SHOULDER_MODE_AUTO] = "Авто (по состоянию)",
