    [SI_BAV_SETTING_SHOULDER_SIDE_NAME] = "Сторона (Авто)",
    [SI_BAV_SETTING_SHOULDER_SIDE_TOOLTIP] = "За какое плечо смещается камера в режиме «Авто».",
