    [SI_BAV_SETTING_SHOULDER_STATE_SPRINT_TOOLTIP] = "Смещать камеру за плечо при беге пешком.",

    [SI_BAV_HEADER_VELOCITY_FOV] = "Поле зрения от скорости",
    [SI_BAV_SECTION_VELOCITY_FOV_HOW] = "|cC5C29EКак это работает вместе с другими функциями|r\n|c8C8A82• Прибавка от скорости |rдобавляется поверх|c8C8A82 динамического FOV (от зума) - они складываются, а не конфликтуют.\n• Если контекстный пресет фиксирует FOV для текущего состояния (например «Бой» или «Спринт»), |rприоритет у пресета|c8C8A82 - прибавка от скорости приостанавливается, пока вы в этом состоянии, и возвращается, когда вы из него выходите.\n• Считывается ваша настоящая скорость движения, поэтому спринт, маунт, плавание и баффы скорости питают один и тот же эффект - настраивать что-то по состояниям не нужно.|r",
    [SI_BAV_SECTION_VELOCITY_FOV_DESCRIPTION] = "|c8C8A82Расширяет поле зрения тем сильнее, чем быстрее вы реально движетесь - спринт, верхом, вплавь или под любым баффом скорости - создавая кинематографичное ощущение скорости, и плавно возвращает его при замедлении. Считывает вашу настоящую скорость движения, поэтому реагирует на любой источник. Добавляется поверх динамического FOV и работает самостоятельно, когда динамический FOV выключен. |r|c6FCB9FВключено по умолчанию.|r",
    [SI_BAV_SETTING_VELOCITY_FOV_ENABLED_NAME] = "Включить поле зрения от скорости",
    [SI_BAV_SETTING_VELOCITY_FOV_ENABLED_TOOLTIP] = "Если включено, поле зрения от третьего лица плавно расширяется тем сильнее, чем быстрее вы движетесь, и плавно возвращается при замедлении.",
    [SI_BAV_SETTING_VELOCITY_FOV_DEBUG_NAME] = "Показать отладочный оверлей",
    [SI_BAV_SETTING_VELOCITY_FOV_DEBUG_TOOLTIP] = "Показывает на экране небольшую сводку: вашу текущую скорость движения, текущую прибавку и позицию - удобно для калибровки эффекта. Выводится только на экран, никогда в чат, и может оставаться включённым независимо от самого эффекта. По умолчанию отключено.",
    [SI_BAV_SETTING_VELOCITY_FOV_SENSITIVITY_NAME] = "Чувствительность",
    [SI_BAV_SETTING_VELOCITY_FOV_SENSITIVITY_TOOLTIP] = "Насколько сильно поле зрения расширяется на скорости: от 0% (без изменения) до 100% (самое сильное расширение). Движок ограничивает итоговый FOV допустимым диапазоном.",

